<?php require_once 'db.php'; $u=require_login('student'); $tables=pdo()->query('SELECT * FROM library_tables ORDER BY floor_no,zone,table_code')->fetchAll(); app_header('Table Booking'); ?><section class="card wide"><h1>Select Study Table</h1><form method="get" action="payment.php" id="bookingForm"><div class="plans"><label><input type="radio" name="days" value="30" checked> 1 Month / 30 Days — ₹800</label><label><input type="radio" name="days" value="90"> 3 Months / 90 Days — ₹2200</label></div><input type="hidden" name="table_id" id="selectedTable" required><div class="seat-map"><?php foreach($tables as $t): $blocked=$t['status']!=='available'||active_overlap_exists((int)$t['id']); ?><button type="button" class="seat <?=$blocked?'blocked':''?>" data-id="<?=e($t['id'])?>" <?=$blocked?'disabled':''?>><?=e($t['table_code'])?></button><?php endforeach; ?></div><button class="btn" id="continueBtn" disabled>Continue to payment</button></form></section><script src="assets/js/seat-booking.js"></script><?php app_footer(); ?>
